#!/usr/bin/env node
import { readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const repoRoot = process.cwd();
const ledgerPath = path.join(repoRoot, 'open-source/gnosis/THEOREM_LEDGER.md');
const reportPath = path.join(repoRoot, 'open-source/gnosis/DUPLICATE_THEOREM_IDS.md');

function rowCells(line) {
  return line
    .split('|')
    .slice(1, -1)
    .map((cell) => cell.trim());
}

function rowId(cell) {
  const match = cell.match(/^`?([^`\s]+)`?/u);
  return match?.[1] ?? null;
}

const rows = readFileSync(ledgerPath, 'utf8').split('\n');
const byId = new Map();

rows.forEach((line, index) => {
  if (!line.startsWith('|') || line.includes('---')) return;
  const cells = rowCells(line);
  if (cells.length < 4) return;
  const id = rowId(cells[0]);
  if (!id?.startsWith('THM-') && !id?.startsWith('ANTI-THM-')) return;
  const entries = byId.get(id) ?? [];
  entries.push({
    lineNumber: index + 1,
    statement: cells[1] ?? '',
    leanReference: cells[3] ?? cells[2] ?? '',
  });
  byId.set(id, entries);
});

const duplicateGroups = [...byId.entries()]
  .filter(([, entries]) => entries.length > 1)
  .sort(([left], [right]) => left.localeCompare(right));

const lines = [
  '# Duplicate Theorem IDs',
  '',
  'Parent: [Gnosis](./README.md)',
  '',
  'Generated by `node open-source/gnosis/scripts/audit-ledger-duplicate-theorem-ids.mjs`.',
  '',
  'Rows are grouped when the same theorem-ledger ID appears in more than one table row.',
  '',
  '## Summary',
  '',
  `- Duplicate theorem ID groups: ${duplicateGroups.length}`,
  `- Duplicate rows beyond one canonical row: ${duplicateGroups.reduce((total, [, entries]) => total + entries.length - 1, 0)}`,
  '',
  '## Duplicate Groups',
  '',
  '| Theorem ID | Row lines | Statements |',
  '|---|---|---|',
];

for (const [id, entries] of duplicateGroups) {
  const lineNumbers = entries.map((entry) => entry.lineNumber).join(', ');
  const statements = entries
    .map((entry) => entry.statement.replaceAll('|', '\\|'))
    .join('<br>');
  lines.push(`| \`${id}\` | ${lineNumbers} | ${statements} |`);
}

writeFileSync(reportPath, `${lines.join('\n')}\n`, 'utf8');
console.log(`Wrote ${path.relative(repoRoot, reportPath)}`);
console.log(`Duplicate theorem ID groups: ${duplicateGroups.length}`);
